import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
def pkgs(data):
    d = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                d[(name, pkg['id'])] = pkg['resolvedVersion']
    return d
bp, ap = pkgs(b), pkgs(a)
if bp == ap: print('All packages match - conversion is version-neutral')
else:
    for k in set(list(bp.keys()) + list(ap.keys())):
        if bp.get(k) != ap.get(k): print(f'DIFF {k}: {bp.get(k)} -> {ap.get(k)}')
"

